import{_ as a,c as i,o,a2 as s}from"./chunks/framework.CIiVzG-O.js";const p=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1776396452000}'),t={name:"guide/faq.md"};function r(n,e,l,c,h,d){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="general-questions" tabindex="-1">General Questions <a class="header-anchor" href="#general-questions" aria-label="Permalink to &quot;General Questions&quot;">​</a></h2><h3 id="what-is-nicasa" tabindex="-1">What is Nicasa? <a class="header-anchor" href="#what-is-nicasa" aria-label="Permalink to &quot;What is Nicasa?&quot;">​</a></h3><p>Nicasa is a modern desktop image viewer and screenshot tool designed exclusively for macOS. It provides fast, intuitive navigation through your image collections with a clean, responsive interface and powerful AI editing capabilities.</p><h3 id="is-nicasa-free" tabindex="-1">Is Nicasa free? <a class="header-anchor" href="#is-nicasa-free" aria-label="Permalink to &quot;Is Nicasa free?&quot;">​</a></h3><p>The Chrome extension is completely free to download and use. The macOS app requires a one-time purchase of $4.99 for full access to all features.</p><h3 id="which-operating-systems-are-supported" tabindex="-1">Which operating systems are supported? <a class="header-anchor" href="#which-operating-systems-are-supported" aria-label="Permalink to &quot;Which operating systems are supported?&quot;">​</a></h3><p>Nicasa is currently available exclusively for macOS 10.13 or later. Windows and Linux versions are not available at this time.</p><h3 id="how-do-i-update-nicasa" tabindex="-1">How do I update Nicasa? <a class="header-anchor" href="#how-do-i-update-nicasa" aria-label="Permalink to &quot;How do I update Nicasa?&quot;">​</a></h3><p>Updates are handled through the Mac App Store. You&#39;ll receive notifications when updates are available, and can update directly through the App Store application.</p><h2 id="usage-questions" tabindex="-1">Usage Questions <a class="header-anchor" href="#usage-questions" aria-label="Permalink to &quot;Usage Questions&quot;">​</a></h2><h3 id="how-do-i-take-screenshots-with-nicasa" tabindex="-1">How do I take screenshots with Nicasa? <a class="header-anchor" href="#how-do-i-take-screenshots-with-nicasa" aria-label="Permalink to &quot;How do I take screenshots with Nicasa?&quot;">​</a></h3><ol><li>Launch Nicasa</li><li>Click the screenshot button in the toolbar or use <code>Cmd+S</code></li><li>Select the area you want to capture</li><li>The screenshot will open in Nicasa for immediate editing</li></ol><h3 id="does-nicasa-work-with-web-images" tabindex="-1">Does Nicasa work with web images? <a class="header-anchor" href="#does-nicasa-work-with-web-images" aria-label="Permalink to &quot;Does Nicasa work with web images?&quot;">​</a></h3><p>Yes! Install the free Nicasa Chrome extension to:</p><ul><li>View all images from any website in one place</li><li>Extract and browse images instantly</li><li>Open images directly in Nicasa for enhanced viewing</li></ul><h3 id="what-ai-editing-features-are-available" tabindex="-1">What AI editing features are available? <a class="header-anchor" href="#what-ai-editing-features-are-available" aria-label="Permalink to &quot;What AI editing features are available?&quot;">​</a></h3><p>Nicasa includes powerful AI tools:</p><ul><li><strong>Auto Enhance</strong>: Automatically improve image quality</li><li><strong>Smart Crop</strong>: Intelligent cropping suggestions</li><li><strong>Inpainting</strong>: Remove unwanted objects intelligently</li><li><strong>Color Correction</strong>: AI-powered color adjustments</li><li><strong>Noise Reduction</strong>: Remove noise and grain</li></ul><h3 id="how-does-transparent-overlay-mode-work" tabindex="-1">How does Transparent Overlay Mode work? <a class="header-anchor" href="#how-does-transparent-overlay-mode-work" aria-label="Permalink to &quot;How does Transparent Overlay Mode work?&quot;">​</a></h3><p>Perfect for designers and artists:</p><ul><li>Pin images above all windows with adjustable transparency</li><li>Use for tracing, reference work, or UI comparison</li><li>Maintains position across all applications</li></ul><h2 id="technical-questions" tabindex="-1">Technical Questions <a class="header-anchor" href="#technical-questions" aria-label="Permalink to &quot;Technical Questions&quot;">​</a></h2><h3 id="why-do-i-need-to-grant-screen-recording-permission" tabindex="-1">Why do I need to grant screen recording permission? <a class="header-anchor" href="#why-do-i-need-to-grant-screen-recording-permission" aria-label="Permalink to &quot;Why do I need to grant screen recording permission?&quot;">​</a></h3><p>Screen recording permission is required for the screenshot functionality. This allows Nicasa to capture your screen when you use the screenshot tool.</p><h3 id="can-i-use-nicasa-offline" tabindex="-1">Can I use Nicasa offline? <a class="header-anchor" href="#can-i-use-nicasa-offline" aria-label="Permalink to &quot;Can I use Nicasa offline?&quot;">​</a></h3><p>Yes. The macOS app works fully offline for local image files. Web image extraction through the Chrome extension requires an active internet connection.</p><h3 id="which-macos-versions-are-supported" tabindex="-1">Which macOS versions are supported? <a class="header-anchor" href="#which-macos-versions-are-supported" aria-label="Permalink to &quot;Which macOS versions are supported?&quot;">​</a></h3><p>Nicasa supports macOS 10.13 or later. It is optimized for Apple Silicon and runs natively on M-series chips.</p><h3 id="what-permissions-does-the-chrome-extension-need" tabindex="-1">What permissions does the Chrome extension need? <a class="header-anchor" href="#what-permissions-does-the-chrome-extension-need" aria-label="Permalink to &quot;What permissions does the Chrome extension need?&quot;">​</a></h3><p>The extension requests access to page content solely to extract image URLs. No browsing history is read or stored.</p><h3 id="is-my-data-uploaded-anywhere" tabindex="-1">Is my data uploaded anywhere? <a class="header-anchor" href="#is-my-data-uploaded-anywhere" aria-label="Permalink to &quot;Is my data uploaded anywhere?&quot;">​</a></h3><p>No. All processing happens locally on your device. Nicasa does not collect, transmit, or store your images.</p><h3 id="how-do-i-backup-my-settings" tabindex="-1">How do I backup my settings? <a class="header-anchor" href="#how-do-i-backup-my-settings" aria-label="Permalink to &quot;How do I backup my settings?&quot;">​</a></h3><p>Your settings are stored locally. To backup:</p><ol><li>Go to Nicasa &gt; Preferences</li><li>Export your settings if available</li><li>Or manually backup the application preferences folder</li></ol><p>Settings are stored in the application data folder. Copy this folder to backup your preferences.</p><h3 id="is-there-a-portable-version" tabindex="-1">Is there a portable version? <a class="header-anchor" href="#is-there-a-portable-version" aria-label="Permalink to &quot;Is there a portable version?&quot;">​</a></h3><p>A portable version is available for Windows. Download it from our website.</p><h2 id="development-questions" tabindex="-1">Development Questions <a class="header-anchor" href="#development-questions" aria-label="Permalink to &quot;Development Questions&quot;">​</a></h2><h3 id="can-i-contribute-to-nicasa" tabindex="-1">Can I contribute to Nicasa? <a class="header-anchor" href="#can-i-contribute-to-nicasa" aria-label="Permalink to &quot;Can I contribute to Nicasa?&quot;">​</a></h3><p>Yes! Nicasa is open source. Visit our <a href="https://github.com/nicasa-project/nicasa" target="_blank" rel="noreferrer">GitHub repository</a> to contribute code, report issues, or suggest features.</p><h3 id="how-do-i-build-nicasa-from-source" tabindex="-1">How do I build Nicasa from source? <a class="header-anchor" href="#how-do-i-build-nicasa-from-source" aria-label="Permalink to &quot;How do I build Nicasa from source?&quot;">​</a></h3><p>See our developer documentation on GitHub for build instructions.</p><h3 id="what-technologies-does-nicasa-use" tabindex="-1">What technologies does Nicasa use? <a class="header-anchor" href="#what-technologies-does-nicasa-use" aria-label="Permalink to &quot;What technologies does Nicasa use?&quot;">​</a></h3><p>Nicasa is built with modern web technologies including Electron for the desktop wrapper and Vue.js for the interface.</p><h2 id="privacy-questions" tabindex="-1">Privacy Questions <a class="header-anchor" href="#privacy-questions" aria-label="Permalink to &quot;Privacy Questions&quot;">​</a></h2><h3 id="does-nicasa-collect-any-data" tabindex="-1">Does Nicasa collect any data? <a class="header-anchor" href="#does-nicasa-collect-any-data" aria-label="Permalink to &quot;Does Nicasa collect any data?&quot;">​</a></h3><p>No, Nicasa does not collect or transmit any personal data. All image processing happens locally on your device.</p><h3 id="are-my-images-safe" tabindex="-1">Are my images safe? <a class="header-anchor" href="#are-my-images-safe" aria-label="Permalink to &quot;Are my images safe?&quot;">​</a></h3><p>Yes, Nicasa only accesses images you explicitly open. It doesn&#39;t upload or share your files.</p><h3 id="what-permissions-does-nicasa-need" tabindex="-1">What permissions does Nicasa need? <a class="header-anchor" href="#what-permissions-does-nicasa-need" aria-label="Permalink to &quot;What permissions does Nicasa need?&quot;">​</a></h3><p>Nicasa needs access to your file system to read images and save settings. It doesn&#39;t require internet access to function.</p><h2 id="still-have-questions" tabindex="-1">Still Have Questions? <a class="header-anchor" href="#still-have-questions" aria-label="Permalink to &quot;Still Have Questions?&quot;">​</a></h2><p>If you can&#39;t find the answer here, please:</p><ol><li>Check our <a href="./../">full documentation</a></li><li>Search our <a href="https://github.com/nicasa-project/nicasa-support/issues" target="_blank" rel="noreferrer">GitHub issues</a></li><li>Create a new issue if needed</li></ol><p>We&#39;re here to help!</p>',57)])])}const m=a(t,[["render",r]]);export{p as __pageData,m as default};
